SELECT
  asset_id,
  overall_impact,
  direct_impact,
  cascading_impact,
  impact_level,
  rank_overall,
  percentile
FROM calculate_impact_batch(
  '[
    {
      "asset_id": "db-prod-auth-01",
      "aggregation_method": "weighted_sum",
      "enable_cascade": true,
      "parameters": [
        {"param_name":"criticality",  "param_value":95,"param_weight":0.60,"impact_category":"direct"},
        {"param_name":"dependencies", "param_value":22,"param_weight":0.40,"max_value":50,"impact_category":"cascading"}
      ]
    },
    {
      "asset_id": "api-gateway-prod",
      "aggregation_method": "weighted_sum",
      "enable_cascade": true,
      "parameters": [
        {"param_name":"criticality",  "param_value":80,"param_weight":0.60,"impact_category":"direct"},
        {"param_name":"dependencies", "param_value":35,"param_weight":0.40,"max_value":50,"impact_category":"cascading"}
      ]
    }
  ]'::JSONB
)
ORDER BY rank_overall;

SELECT
  overall_impact,
  direct_impact,
  indirect_impact,
  impact_by_category
FROM calculate_impact_from_json(
  '{
    "aggregation_method": "weighted_sum",
    "scale_to": 100,
    "enable_cascade": false,
    "parameters": [
      {"param_name":"data_exposure_severity", "param_value":92, "param_weight":0.50, "max_value":100, "impact_category":"direct"},
      {"param_name":"downtime_risk_hours", "param_value":4, "param_weight":0.30, "max_value":24, "impact_category":"direct"},
      {"param_name":"regulatory_fines_risk", "param_value":75, "param_weight":0.20, "max_value":100, "impact_category":"indirect"}
    ]
  }'::JSONB
);

